class Solution {
public:
    int strongPasswordChecker(string password) {
        int n = password.size();
        int lower = 0, upper = 0, digit = 0;
        int repeat = 0, last = 0;
        int maxRepeat = 0;
        for (int i = 0; i < n; i++) {
            if (password[i] >= 'a' && password[i] <= 'z') lower++;
            else if (password[i] >= 'A' && password[i] <= 'Z') upper++;
            else if (password[i] >= '0' && password[i] <= '9') digit++;
            if (i > 0 && password[i] == password[i - 1]) repeat++;
            else repeat = 0;
            if (repeat == 2) {
                maxRepeat = max(maxRepeat, i - last);
                last = i;
            }
        }
        int missing = 26 + 26 + 10 - lower - upper - digit;
        if (n < 6) return max(missing, 6 - n);
        if (n <= 20) return max(missing, maxRepeat);
        int del = n - 20;
        missing = max(missing - del, 0);
        return max(missing, maxRepeat);
    }
};
